  1→/**
  2→ * Project API Client
  3→ *
  4→ * TypeScript client for Project API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on projects.
  6→ */
  7→
  8→import type {
  9→  ProjectData,
 10→  ProjectStageData,
 11→  ProjectListParams,
 12→  ProjectCreateInput,
 13→  ProjectUpdateInput,
 14→  ProjectStageUpdateInput,
 15→  ApiListResponse,
 16→  ApiResponse,
 17→  ApiClientConfig,
 18→} from './types';
 19→import { ApiClientError, parseApiError, parseJson } from './shared';
 20→
 21→export { ApiClientError } from './shared';
 22→
 23→/**
 24→ * Default base URL for API requests
 25→ */
 26→const DEFAULT_BASE_URL = '/api';
 27→
 28→/**
 29→ * Project API Client
 30→ *
 31→ * Provides typed methods for Project CRUD operations.
 32→ */
 33→export class ProjectApiClient {
 34→  private baseUrl: string;
 35→  private fetchFn: typeof globalThis.fetch;
 36→  private defaultHeaders: Record<string, string>;
 37→
 38→  constructor(config: ApiClientConfig = {}) {
 39→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 40→    this.fetchFn = config.fetch ?? fetch;
 41→    this.defaultHeaders = {
 42→      'Content-Type': 'application/json',
 43→      ...config.headers,
 44→    };
 45→  }
 46→
 47→  /**
 48→   * Build full URL for endpoint
 49→   */
 50→  private url(path: string, params?: Record<string, string | undefined>): string {
 51→    const fullUrl = `${this.baseUrl}${path}`;
 52→
 53→    if (params) {
 54→      const searchParams = new URLSearchParams();
 55→      for (const [key, value] of Object.entries(params)) {
 56→        if (value !== undefined) {
 57→          searchParams.append(key, value);
 58→        }
 59→      }
 60→      const queryString = searchParams.toString();
 61→      if (queryString) {
 62→        return `${fullUrl}?${queryString}`;
 63→      }
 64→    }
 65→
 66→    return fullUrl;
 67→  }
 68→
 69→  /**
 70→   * GET /api/projects
 71→   *
 72→   * List all projects with optional filtering.
 73→   */
 74→  async getProjects(params?: ProjectListParams): Promise<ApiListResponse<ProjectData>> {
 75→    const response = await this.fetchFn(
 76→      this.url('/projects', {
 77→        status: params?.status,
 78→        managerId: params?.managerId,
 79→        contactId: params?.contactId,
 80→        dealId: params?.dealId,
 81→        skip: params?.skip?.toString(),
 82→        take: params?.take?.toString(),
 83→      }),
 84→      {
 85→        headers: this.defaultHeaders,
 86→      }
 87→    );
 88→
 89→    if (!response.ok) {
 90→      return parseApiError(response);
 91→    }
 92→
 93→    return parseJson<ApiListResponse<ProjectData>>(response);
 94→  }
 95→
 96→  /**
 97→   * GET /api/projects/[id]
 98→   *
 99→   * Fetch a single project by ID.
100→   */
101→  async getProject(id: string): Promise<ApiResponse<ProjectData>> {
102→    if (!id) {
103→      throw new ApiClientError(400, 'Validation failed', 'id is required');
104→    }
105→
106→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
107→      headers: this.defaultHeaders,
108→    });
109→
110→    if (!response.ok) {
111→      return parseApiError(response);
112→    }
113→
114→    return parseJson<ApiResponse<ProjectData>>(response);
115→  }
116→
117→  /**
118→   * POST /api/projects
119→   *
120→   * Create a new project.
121→   */
122→  async createProject(data: ProjectCreateInput): Promise<ApiResponse<ProjectData>> {
123→    const response = await this.fetchFn(this.url('/projects'), {
124→      method: 'POST',
125→      headers: this.defaultHeaders,
126→      body: JSON.stringify(data),
127→    });
128→
129→    if (!response.ok) {
130→      return parseApiError(response);
131→    }
132→
133→    return parseJson<ApiResponse<ProjectData>>(response);
134→  }
135→
136→  /**
137→   * PATCH /api/projects/[id]
138→   *
139→   * Update an existing project.
140→   */
141→  async updateProject(
142→    id: string,
143→    data: ProjectUpdateInput
144→  ): Promise<ApiResponse<ProjectData>> {
145→    if (!id) {
146→      throw new ApiClientError(400, 'Validation failed', 'id is required');
147→    }
148→
149→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
150→      method: 'PATCH',
151→      headers: this.defaultHeaders,
152→      body: JSON.stringify(data),
153→    });
154→
155→    if (!response.ok) {
156→      return parseApiError(response);
157→    }
158→
159→    return parseJson<ApiResponse<ProjectData>>(response);
160→  }
161→
162→  /**
163→   * DELETE /api/projects/[id]
164→   *
165→   * Soft-delete a project.
166→   */
167→  async deleteProject(id: string): Promise<ApiResponse<ProjectData>> {
168→    if (!id) {
169→      throw new ApiClientError(400, 'Validation failed', 'id is required');
170→    }
171→
172→    const response = await this.fetchFn(this.url(`/projects/${id}`), {
173→      method: 'DELETE',
174→      headers: this.defaultHeaders,
175→    });
176→
177→    if (!response.ok) {
178→      return parseApiError(response);
179→    }
180→
181→    return parseJson<ApiResponse<ProjectData>>(response);
182→  }
183→
184→  /**
185→   * PATCH /api/projects/[id]/stages/[stageId]
186→   *
187→   * Update a project stage's dates via drag-drop.
188→   */
189→  async updateStage(
190→    projectId: string,
191→    stageId: string,
192→    data: ProjectStageUpdateInput
193→  ): Promise<ApiResponse<ProjectStageData>> {
194→    if (!projectId || !stageId) {
195→      throw new ApiClientError(400, 'Validation failed', 'projectId and stageId are required');
196→    }
197→
198→    const response = await this.fetchFn(
199→      this.url(`/projects/${projectId}/stages/${stageId}`),
200→      {
201→        method: 'PATCH',
202→        headers: this.defaultHeaders,
203→        body: JSON.stringify(data),
204→      }
205→    );
206→
207→    if (!response.ok) {
208→      return parseApiError(response);
209→    }
210→
211→    return parseJson<ApiResponse<ProjectStageData>>(response);
212→  }
213→}
