  1→/**
  2→ * ProductionRepository - CRUD operations for Production model
  3→ *
  4→ * Provides typed methods for Production queries with soft-delete support.
  5→ * Handles Production stage transitions with proper cascade behavior.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Production,
 11→  ProductionStage,
 12→  Prisma,
 13→} from '@prisma/client';
 14→import { randomUUID } from 'node:crypto';
 15→
 16→/**
 17→ * Production creation input type
 18→ */
 19→export type ProductionCreateInput = Omit<Prisma.ProductionUncheckedCreateInput, 'id' | 'updatedAt'> & Partial<Pick<Prisma.ProductionUncheckedCreateInput, 'id' | 'updatedAt'>>;
 20→
 21→/**
 22→ * Production update input type
 23→ */
 24→export type ProductionUpdateInput = Prisma.ProductionUncheckedUpdateInput;
 25→
 26→/**
 27→ * Production findMany params type
 28→ */
 29→export type ProductionFindManyParams = {
 30→  where?: Prisma.ProductionWhereInput;
 31→  orderBy?: Prisma.ProductionOrderByWithRelationInput;
 32→  skip?: number;
 33→  take?: number;
 34→  include?: Prisma.ProductionInclude;
 35→};
 36→
 37→/**
 38→ * ProductionStage creation input type
 39→ */
 40→export type ProductionStageCreateInput = Omit<Prisma.ProductionStageUncheckedCreateInput, 'id' | 'updatedAt'> & Partial<Pick<Prisma.ProductionStageUncheckedCreateInput, 'id' | 'updatedAt'>>;
 41→
 42→/**
 43→ * ProductionStage update input type
 44→ */
 45→export type ProductionStageUpdateInput = Prisma.ProductionStageUncheckedUpdateInput;
 46→
 47→/**
 48→ * Repository for Production CRUD operations
 49→ */
 50→export class ProductionRepository {
 51→  /**
 52→   * Find many productions with optional filtering
 53→   * Automatically filters out soft-deleted records
 54→   */
 55→  async findMany(params?: ProductionFindManyParams): Promise<Production[]> {
 56→    const { where, ...rest } = params ?? {};
 57→
 58→    return prisma.production.findMany({
 59→      ...rest,
 60→      where: {
 61→        ...where,
 62→        deletedAt: null, // Always exclude soft-deleted
 63→      },
 64→    });
 65→  }
 66→
 67→  /**
 68→   * Find a single production by ID
 69→   * Returns null if not found or soft-deleted
 70→   */
 71→  async findUnique(
 72→    id: string,
 73→    include?: Prisma.ProductionInclude
 74→  ): Promise<Production | null> {
 75→    return prisma.production.findFirst({
 76→      where: { id, deletedAt: null },
 77→      include,
 78→    });
 79→  }
 80→
 81→  /**
 82→   * Find productions by project ID
 83→   */
 84→  async findByProject(projectId: string): Promise<Production[]> {
 85→    return this.findMany({
 86→      where: { projectId },
 87→      orderBy: { createdAt: 'desc' },
 88→    });
 89→  }
 90→
 91→  /**
 92→   * Find productions by status
 93→   */
 94→  async findByStatus(status: string): Promise<Production[]> {
 95→    return this.findMany({
 96→      where: { status },
 97→      orderBy: { createdAt: 'desc' },
 98→    });
 99→  }
100→
101→  /**
102→   * Create a new production
103→   * Generates UUID and timestamps if not provided
104→   */
105→  async create(data: ProductionCreateInput): Promise<Production> {
106→    const now = new Date();
107→
108→    return prisma.production.create({
109→      data: {
110→        ...data,
111→        id: data.id ?? randomUUID(),
112→        createdAt: data.createdAt ?? now,
113→        updatedAt: data.updatedAt ?? now,
114→      },
115→    });
116→  }
117→
118→  /**
119→   * Update an existing production
120→   * Throws RecordNotFound if production doesn't exist or is soft-deleted
121→   */
122→  async update(
123→    id: string,
124→    data: ProductionUpdateInput
125→  ): Promise<Production> {
126→    // Verify production exists and not deleted
127→    const existing = await this.findUnique(id);
128→    if (!existing) {
129→      throw new Error(`Production with id ${id} not found`);
130→    }
131→
132→    return prisma.production.update({
133→      where: { id },
134→      data: {
135→        ...data,
136→        updatedAt: new Date(),
137→      },
138→    });
